 1	import * as React from 'react';
 2	import { Label } from './Label';
 3	import { Button, ButtonVariant, Tooltip, TooltipPosition } from '@patternfly/react-core';
 4	import { kialiStyle } from 'styles/StyleUtils';
 5	import { KialiIcon } from '../../config/KialiIcon';
 6	import { classes } from 'typestyle';
 7	import { infoStyle } from 'styles/IconStyle';
 8	
 9	const SHOW_MORE_TRESHOLD = 2;
10	
11	interface LabelsProps {
12	  expanded?: boolean;
13	  labels?: { [key: string]: string };
14	  tooltipMessage?: string;
15	  type?: string;
16	}
17	
18	const linkStyle = kialiStyle({
19	  padding: '0 0.25rem',
20	  fontSize: '0.8rem'
21	});
22	
23	const labelInfoStyle = kialiStyle({
24	  marginLeft: '0.125rem',
25	  marginBottom: '0.125rem'
26	});
27	
28	const labelsContainerStyle = kialiStyle({
29	  display: 'flex',
30	  alignItems: 'center',
31	  flexWrap: 'wrap',
32	  overflow: 'hidden'
33	});
34	
35	export const Labels: React.FC<LabelsProps> = (props: LabelsProps) => {
36	  const [expanded, setExpanded] = React.useState<boolean>(props.expanded ?? false);
37	
38	  const labelKeys = Object.keys(props.labels ?? {});
39	
40	  const hasLabels = labelKeys.length > 0;
41	
42	  const hasManyLabels = labelKeys.length > SHOW_MORE_TRESHOLD;
43	
44	  const showItem = (i: number): boolean => {
45	    return expanded || !hasManyLabels || i < SHOW_MORE_TRESHOLD;
46	  };
47	
48	  const expandLabels = (): void => {
49	    setExpanded(true);
50	  };
51	
52	  const renderMoreLabelsLink =
53	    hasManyLabels && !expanded ? (
54	      <Button
55	        data-test="label_more"
56	        key="label_more"
57	        variant={ButtonVariant.link}
58	        className={linkStyle}
59	        onClick={expandLabels}
60	      >
61	        More {props.type ? props.type : 'labels'}...
62	      </Button>
63	    ) : null;
64	
65	  const renderLabels = labelKeys.map((key, i) => {
66	    return showItem(i) ? (
67	      <div key={`label_div_${i}`} data-test={`${key}-label-container`}>
68	        <Label key={`label_${i}`} name={key} value={props.labels ? props.labels[key] : ''} />
69	      </div>
70	    ) : undefined;
71	  });
72	
73	  const renderEmptyLabels = <span> No {props.type ? props.type : 'labels'} </span>;
74	
75	  const tooltip = props.tooltipMessage ? (
76	    <Tooltip
77	      key="tooltip_missing_sidecar"
78	      position={TooltipPosition.auto}
79	      content={<div style={{ textAlign: 'left' }}>{props.tooltipMessage}</div>}
80	    >
81	      <KialiIcon.Info className={classes(infoStyle, labelInfoStyle)} />
82	    </Tooltip>
83	  ) : undefined;
84	
85	  return (
86	    <div className={labelsContainerStyle}>
87	      {hasLabels ? [renderLabels, renderMoreLabelsLink] : renderEmptyLabels}
88	
89	      {tooltip}
90	    </div>
91	  );
92	};

