 1	import * as React from 'react';
 2	import { shallow } from 'enzyme';
 3	import { Labels } from '../Labels';
 4	import { shallowToJson } from 'enzyme-to-json';
 5	
 6	const mockBadge = (labels: { [key: string]: string }) => {
 7	  const component = <Labels labels={labels} />;
 8	  return shallow(component);
 9	};
10	
11	describe('#Labels render correctly with data', () => {
12	  it('should render badges with More labels link', () => {
13	    const wrapper = mockBadge({
14	      app: 'bookinfo',
15	      version: 'v1',
16	      env: 'prod',
17	      team: 'A'
18	    });
19	
20	    expect(shallowToJson(wrapper)).toBeDefined();
21	    expect(shallowToJson(wrapper)).toMatchSnapshot();
22	  });
23	
24	  it('should render badges without More labels link', () => {
25	    const wrapper = mockBadge({
26	      app: 'bookinfo',
27	      version: 'v1'
28	    });
29	
30	    expect(shallowToJson(wrapper)).toBeDefined();
31	    expect(shallowToJson(wrapper)).toMatchSnapshot();
32	  });
33	});

